from fastapi import APIRouter

from app.schemas.common import SkeletonCollectionResponse, empty_collection

router = APIRouter(prefix="/predictions", tags=["predictions"])


@router.get("", response_model=SkeletonCollectionResponse)
def list_predictions() -> SkeletonCollectionResponse:
    return empty_collection(
        "predictions",
        [
            "Prediction creation is disabled in Phase 8.",
            "Published predictions remain append-only and immutable by database design.",
            "No real prediction is generated by this endpoint.",
        ],
    )
